#!/usr/bin/env python3
import base64, gzip, json, pathlib
data = ""
files = json.loads(gzip.decompress(base64.b64decode(data)))
for path, content in files.items():
    p = pathlib.Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(content, encoding="utf-8")
    print(f"  wrote {path}")
print(f"\nDone! {len(files)} files created.")
